-- Repartidor de misiones
lang["#MISSION_GIVER_ORTENO"] = "Ranger Superior Orteno"
lang["#MISSION_GIVER_ORTENO_NEW"] = "Bueno, veo una cara nueva. Me llamo Orteno, y represento a los Rangers del Desierto de Nevada. Hemos hecho causa común con la RNC para hacer segura esta área para viajar y abrir los lugares salvajes para el asentamiento. ¿Te gustaría ayudarnos?"
lang["#MISSION_GIVER_ORTENO_NO"] = "Mira, seré franco contigo: no eres el tipo de persona que queremos cerca, así que te sugiero que te vayas y te vayas ahora."
lang["#MISSION_GIVER_ORTENO_0"] = "¿Hemos...? Oh, espera, no, ahora te recuerdo. ¿Aún interesado en ayudar o es solo una visita social?"
lang["MISSION_GIVER_ORTENO_25"] = "¿Cómo van tus cacerías? Todavía hay mucho más que hacer en el yermo."
lang["MISSION_GIVER_ORTENO_50"] = "Muy bien, creo que confío lo suficiente en ti como para darte acceso a nuestra armería. Ve a hablar con Grant si estás interesado en intercambiar por algo de equipo."
lang["MISSION-GIVER_ORTENO_100"] = "Normalmente no ofrezco este tipo de cosas, pero... bueno, te lo has ganado. Le dije a Grant que te diera acceso al mejor equipo que tenemos en nuestras reservas. Si estás interesado, ahora es el momento."

-- Misiones
lang["#MISSION_ORTENO_INTRO"] = "Introducción a los Rangers del Desierto"
lang["#MISSION_ORTENO_INTRO_DESC"] = "¿Interesado en quedarte a ayudar, verdad? Aceptaré cualquier ayuda que pueda conseguir.\n\nSi no estás familiarizado con nuestra organización, los Rangers del Desierto son pacificadores, jueces y cazadores de élite. En el yermo, la justicia debe ser rápida y decisiva para ser efectiva, y nos esforzamos por ofrecer exactamente eso. Tampoco reclutamos a cualquiera. Si estás interesado, tengo una prueba sencilla para ti; dejé una bala .50 en la cantera, y quiero que vayas a buscarla. Muéstrame tus habilidades de búsqueda y a partir de ahí veremos. Ah, tampoco tiene sentido quedártela; la vaina está perforada y ya no puede aceptar cebos. Es una prueba de iniciación, ¿vale?"
lang["#MISSION_ORTENO_INTRO_HINT"] = "Encuentra la Bala de Orteno en la cantera de Salt Wells. Está en algún lugar de la superficie; ¡recuerda mirar dentro de la torre y las máquinas!"
lang["#MISSION_ORTENO_INTRO_COMPLETE"] = "Sí, esa es. Muy bien, no eres totalmente imperceptivo; creo que podemos encontrar un lugar para ti aquí."
lang["#MISSION_ORTENO_INTRO_ITEMNAME"] = "Bala de Orteno"

lang["#MISSION_ORTENO_SELF"] = "Autosuficiencia"
lang["#MISSION_ORTENO_SELF_DESC"] = "Una de las primeras cosas que querrás aprender como aspirante a Ranger del Desierto es abastecerte de la tierra. Estamos en el campo más a menudo que no; el hambre, la sed y el buen descanso serán mucho más peligrosos para ti que quedarte sin munición. Quiero que salgas y recorras el área y me traigas algunas muestras de la producción local. ¿Puedes hacer eso por mí?"
lang["#MISSION_ORTENO_SELF_HINT"] = "Encuentra Agua Sucia, Fruta de Agave, Fruta de Nopal, Jalapeño, Maíz y Calabaza Búfalo para Orteno. Las plantas se pueden encontrar dispersas por Salt Wells."
lang["#MISSION_ORTENO_SELF_COMPLETE"] = "Buen trabajo. Recuerda; la madre naturaleza siempre proveerá. Recae en ti ser lo suficientemente inteligente para encontrar su generosidad, sin embargo."

lang["#MISSION_ORTENO_TEETH"] = "Cortando los Dientes"
lang["#MISSION_ORTENO_TEETH_DESC"] = "Sé que puedes mantenerte, pero necesito que me demuestres ahora que puedes defenderte a ti mismo y a los demás. No te voy a lanzar a la parte profunda todavía, así que quiero que empieces con los 80 que están acosando a los lugareños. Muéstrales un poco de justicia del yermo."
lang["#MISSION_ORTENO_TEETH_HINT"] = "Mata a cinco bandidos de la Tribu de los 80. Se pueden encontrar en dos campamentos principales; uno cerca de la cantera y otro cerca de Salt Wells al otro lado del puente."
lang["#MISSION_ORTENO_TEETH_COMPLETE"] = "¿Ya terminaste? Estoy sorprendido. Si estás listo, creo que es hora de que te enfrentes a un juego un poco más peligroso."

RELOADSCHEMA = true